{
  "title": "ऑब्जेक्ट कीज़ में Symbol का उपयोग",
  "group": "एडवांस्ड इंटरफेस",
  "options": [
    {
      "text": "एक Symbol का उपयोग करके",
      "hint": "बिल्कुल सही। Symbols गारंटीकृत यूनिक होते हैं।"
    },
    {
      "text": "एक string का उपयोग करके",
      "hint": "स्ट्रिंग्स अक्सर एक्सीडेंट से ओवरराइट हो जाती हैं।"
    },
    {
      "text": "एक number का उपयोग करके",
      "hint": "नंबर्स को ऑटोमैटिकली स्ट्रिंग में बदल दिया जाता है।"
    },
    {
      "text": "एक ऑब्जेक्ट को key के रूप में उपयोग करके",
      "hint": "ऑब्जेक्ट्स को `[object Object]` में बदल दिया जाता है, जो यूनिक नहीं है।"
    }
  ],
  "questionProse": [
    "JavaScript ऑब्जेक्ट के लिए एक वास्तव में यूनिक प्रॉपर्टी key बनाने का सही तरीका क्या है?"
  ],
  "explanationProse": [
    "Symbols एक यूनिक और immutable primitive type हैं जिनका उपयोग ऑब्जेक्ट प्रॉपर्टीज़ की keys के रूप में किया जा सकता है। यह नेम कोलिज़न से बचने में मदद करता है, खासकर बड़े कोडबेस में या रीयूज़ेबल लाइब्रेरीज़ लिखते समय।"
  ]
}
